import{c as a,Q as e,j as s,m as n}from"./chunks/framework.BXc4yaFE.js";const g=JSON.parse('{"title":"Multi-Agent 架構與 Sub-Agent 模式","description":"","frontmatter":{},"headers":[],"relativePath":"resources/best-practices/multi-agent.md","filePath":"resources/best-practices/multi-agent.md","lastUpdated":1779796674000}'),i={name:"resources/best-practices/multi-agent.md"};function r(o,t,l,d,h,p){return e(),s("div",null,[...t[0]||(t[0]=[n(`<h1 id="multi-agent-架構與-sub-agent-模式" tabindex="-1">Multi-Agent 架構與 Sub-Agent 模式 <a class="header-anchor" href="#multi-agent-架構與-sub-agent-模式" aria-label="Permalink to &quot;Multi-Agent 架構與 Sub-Agent 模式&quot;">​</a></h1><p>整合官方文件、社群實戰（claudekit.cc）與 12 個可重用 Harness 模式，系統性地掌握多代理人協作架構。</p><h2 id="sub-agent-的正確定位" tabindex="-1">Sub-Agent 的正確定位 <a class="header-anchor" href="#sub-agent-的正確定位" aria-label="Permalink to &quot;Sub-Agent 的正確定位&quot;">​</a></h2><p>官方文件與 Claude Code 團隊成員 Adam Wolf 的明確指引：</p><blockquote><p>&quot;Sub agents work best when they just looking for information and provide a small amount of summary back to main conversation thread.&quot;</p></blockquote><h3 id="正確用途-vs-錯誤用途" tabindex="-1">正確用途 vs 錯誤用途 <a class="header-anchor" href="#正確用途-vs-錯誤用途" aria-label="Permalink to &quot;正確用途 vs 錯誤用途&quot;">​</a></h3><table tabindex="0"><thead><tr><th>正確用途</th><th>錯誤用途</th></tr></thead><tbody><tr><td>平行蒐集資訊（搜尋、讀取多個檔案）</td><td>平行實作不同模組（每個 agent 都「視野盲目」）</td></tr><tr><td>執行探索性任務（不需完整專案 context）</td><td>跨模組重構（需要完整 context 才能正確推理）</td></tr><tr><td>隔離「會污染主 context 的雜訊」</td><td>序列依賴任務（A 的輸出決定 B 的輸入）</td></tr><tr><td>研究型工作（讀取 log、搜尋結果）</td><td>需要知道彼此決策的協作實作</td></tr></tbody></table><hr><h2 id="拓撲限制" tabindex="-1">拓撲限制 <a class="header-anchor" href="#拓撲限制" aria-label="Permalink to &quot;拓撲限制&quot;">​</a></h2><p>根據官方規範：</p><ul><li><strong>Fan-out 上限 4</strong>：單一 turn 最多同時啟動 4 個 sub-agent</li><li><strong>不支援 sub-agent spawning sub-agent</strong>：child 不能再開 child（防止無限嵌套）</li><li><strong>通訊限 parent ↔ child</strong>：child 間不能直接溝通，只能透過 parent 彙整</li><li><strong>Child 不 self-retry</strong>：失敗必須返回 parent 決策</li></ul><hr><h2 id="explore-→-plan-→-execute-模式" tabindex="-1">Explore → Plan → Execute 模式 <a class="header-anchor" href="#explore-→-plan-→-execute-模式" aria-label="Permalink to &quot;Explore → Plan → Execute 模式&quot;">​</a></h2><p>實戰驗證最有效的三階段架構：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Phase 1 (Sub-agents, parallel):  Explore — 各自蒐集資訊</span></span>
<span class="line"><span>Phase 2 (Main agent):            Plan    — 統整決策</span></span>
<span class="line"><span>Phase 3 (Main agent or 1 agent): Execute — 有完整 context 才實作</span></span></code></pre></div><p><strong>為什麼這樣設計</strong>：Sub-agent 的 context isolation 防止 context rot，但也造成盲點。Phase 1 讓資訊蒐集平行化，Phase 2 讓主 agent 在完整視野下做決策，Phase 3 確保實作者看得見完整架構。</p><hr><h2 id="strategic-model-routing" tabindex="-1">Strategic Model Routing <a class="header-anchor" href="#strategic-model-routing" aria-label="Permalink to &quot;Strategic Model Routing&quot;">​</a></h2><table tabindex="0"><thead><tr><th>角色</th><th>模型</th><th>適用工作</th></tr></thead><tbody><tr><td>主 Agent</td><td>Opus 4.7</td><td>高層次推理、架構決策</td></tr><tr><td>Implementation</td><td>Sonnet 4.6</td><td>中等複雜度的實作工作</td></tr><tr><td>Simple Lookup</td><td>Haiku 4.5</td><td>低成本蒐集、格式化</td></tr></tbody></table><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># .claude/agents/researcher.md 範例</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">---</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">model</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">claude-haiku-4-5</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">allowed-tools</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Read, Grep, Glob, WebSearch</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">description</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Information gathering only. Returns ≤600 word summaries.&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">---</span></span></code></pre></div><hr><h2 id="明確-definition-of-done" tabindex="-1">明確 Definition of Done <a class="header-anchor" href="#明確-definition-of-done" aria-label="Permalink to &quot;明確 Definition of Done&quot;">​</a></h2><p>在 sub-agent prompt 末尾加入驗收 checklist，防止「premature victory declaration」：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## 完成條件（必須全部成立才能回傳）</span></span>
<span class="line"><span>- [ ] 已讀取所有指定路徑的檔案</span></span>
<span class="line"><span>- [ ] 摘要 ≤ 600 字</span></span>
<span class="line"><span>- [ ] 未修改任何檔案（只讀取）</span></span>
<span class="line"><span>- [ ] 若有錯誤，明確說明「失敗原因」而非口頭聲稱成功</span></span></code></pre></div><hr><h2 id="tool-最小化原則" tabindex="-1">Tool 最小化原則 <a class="header-anchor" href="#tool-最小化原則" aria-label="Permalink to &quot;Tool 最小化原則&quot;">​</a></h2><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 不好的設定（給太多工具）</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">allowed-tools</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Read, Write, Edit, Bash, WebSearch, WebFetch</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 好的設定（研究型 agent）</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">allowed-tools</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Read, Grep, Glob</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 好的設定（實作型 agent，只給必要工具）</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">allowed-tools</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Read, Edit, Bash</span></span></code></pre></div><hr><h2 id="_12-個可重用-harness-模式" tabindex="-1">12 個可重用 Harness 模式 <a class="header-anchor" href="#_12-個可重用-harness-模式" aria-label="Permalink to &quot;12 個可重用 Harness 模式&quot;">​</a></h2><p>從 Claude Code 的設計中提煉的 12 個系統性模式，覆蓋四大領域：</p><h3 id="記憶與上下文-5-個模式" tabindex="-1">記憶與上下文（5 個模式） <a class="header-anchor" href="#記憶與上下文-5-個模式" aria-label="Permalink to &quot;記憶與上下文（5 個模式）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>模式</th><th>說明</th></tr></thead><tbody><tr><td><strong>Persistent Instruction File</strong></td><td>配置檔案在 Session 啟動時自動注入，定義架構規則與命名約定</td></tr><tr><td><strong>Scoped Context Assembly</strong></td><td>指令按工作目錄動態加載，支持單體倉庫的分層規則</td></tr><tr><td><strong>Tiered Memory</strong></td><td>精簡索引常駐上下文，細節按需加載，完整日誌離線存儲</td></tr><tr><td><strong>Dream Consolidation</strong></td><td>背景進程定期去重複與剪除過時記憶，防止索引膨脹</td></tr><tr><td><strong>Progressive Context Compaction</strong></td><td>近期交互保留細節，舊交互逐層摘要化，支持 20-30+ 輪</td></tr></tbody></table><blockquote><p><strong>核心思路</strong>：高頻訪問的決策常駐 context，低頻歷史卸載至磁盤——「主記憶」與「輔助儲存」的二級制。</p></blockquote><h3 id="工作流程與編排-3-個模式" tabindex="-1">工作流程與編排（3 個模式） <a class="header-anchor" href="#工作流程與編排-3-個模式" aria-label="Permalink to &quot;工作流程與編排（3 個模式）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>模式</th><th>說明</th></tr></thead><tbody><tr><td><strong>Explore-Plan-Act Loop</strong></td><td>唯讀研究 → 規劃討論 → 代碼變更，權限逐級提升</td></tr><tr><td><strong>Context-Isolated Subagents</strong></td><td>角色特定的沙箱化上下文，防止工作階段污染</td></tr><tr><td><strong>Fork-Join Parallelism</strong></td><td>多 Subagent 並行工作，隔離倉庫副本，合併結果</td></tr></tbody></table><h3 id="工具與權限-3-個模式" tabindex="-1">工具與權限（3 個模式） <a class="header-anchor" href="#工具與權限-3-個模式" aria-label="Permalink to &quot;工具與權限（3 個模式）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>模式</th><th>說明</th></tr></thead><tbody><tr><td><strong>Progressive Tool Expansion</strong></td><td>最小工具集（&lt;20）默認加載，專化工具按需啟用</td></tr><tr><td><strong>Command Risk Classification</strong></td><td>確定性風險評估，低風險自動批准，高風險人工審批</td></tr><tr><td><strong>Single-Purpose Tool Design</strong></td><td>特定工具替代通用 Shell，提升可審計性</td></tr></tbody></table><h3 id="自動化-1-個模式" tabindex="-1">自動化（1 個模式） <a class="header-anchor" href="#自動化-1-個模式" aria-label="Permalink to &quot;自動化（1 個模式）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>模式</th><th>說明</th></tr></thead><tbody><tr><td><strong>Deterministic Lifecycle Hooks</strong></td><td>25+ 鉤子綁定生命週期事件，可靠執行程序步驟，不依賴模型記憶</td></tr></tbody></table><hr><h2 id="thin-harness-fat-skills-garry-tan" tabindex="-1">Thin Harness, Fat Skills（Garry Tan） <a class="header-anchor" href="#thin-harness-fat-skills-garry-tan" aria-label="Permalink to &quot;Thin Harness, Fat Skills（Garry Tan）&quot;">​</a></h2><p>Garry Tan 的核心原則：harness 應只做四件事：</p><ol><li><strong>Run the model in a loop</strong></li><li><strong>Read and write files</strong></li><li><strong>Manage context</strong></li><li><strong>Enforce safety</strong></li></ol><p><strong>Fat Harness 的問題</strong>：過多的工具定義消耗 context window，引入效能瓶頸。量化案例：Playwright CLI 執行瀏覽器操作只需 100ms，Chrome MCP 需要 15 秒——<strong>75 倍差距</strong>。</p><p><strong>解決方案：方向性架構</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Intelligence ↑  → Skill Files（可重用指令）</span></span>
<span class="line"><span>Execution   ↓  → Deterministic Tools（確定性工具）</span></span>
<span class="line"><span>Middle Layer   → 盡可能薄</span></span></code></pre></div><blockquote><p>&quot;Every skill you write is a permanent upgrade to your system.&quot; — Garry Tan</p></blockquote><p>Skill 在模型升級時自動受益（智慧提升），Deterministic Tool 保持可靠（確定性不變）。</p><hr><h2 id="失敗模式速覽-六大類-38-個-gotcha" tabindex="-1">失敗模式速覽（六大類 38 個 Gotcha） <a class="header-anchor" href="#失敗模式速覽-六大類-38-個-gotcha" aria-label="Permalink to &quot;失敗模式速覽（六大類 38 個 Gotcha）&quot;">​</a></h2><h3 id="delegation-trigger-失敗" tabindex="-1">Delegation Trigger 失敗 <a class="header-anchor" href="#delegation-trigger-失敗" aria-label="Permalink to &quot;Delegation Trigger 失敗&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Gotcha</th><th>症狀</th><th>修復</th></tr></thead><tbody><tr><td>自動委派過於保守</td><td>Opus/Sonnet 傾向自己處理</td><td>在 CLAUDE.md 明確寫「Spawn multiple subagents when...」</td></tr><tr><td>Agent type 選錯</td><td>researcher 開始寫程式碼</td><td>Agent description 加明確禁止清單</td></tr><tr><td>Fan-out 過小</td><td>3 個任務只啟動 1 個 sub-agent</td><td>明確說「請同時委派給 3 個 sub-agent」</td></tr></tbody></table><h3 id="context-isolation-失敗" tabindex="-1">Context Isolation 失敗 <a class="header-anchor" href="#context-isolation-失敗" aria-label="Permalink to &quot;Context Isolation 失敗&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Gotcha</th><th>症狀</th><th>修復</th></tr></thead><tbody><tr><td>Sub-agent 重複工作</td><td>兩個 agent 讀同一個檔案</td><td>Fan-out 前明確分配任務邊界</td></tr><tr><td>Sub-agent 架構不一致</td><td>Frontend agent 的決策與 Backend 衝突</td><td>Execute phase 集中在主 agent，sub-agent 只 Explore</td></tr><tr><td>忘記隔離 context</td><td>Sub-agent 看到主線 context 污染</td><td>驗證 sub-agent system prompt 不引用主線狀態</td></tr></tbody></table><h3 id="輸出品質失敗" tabindex="-1">輸出品質失敗 <a class="header-anchor" href="#輸出品質失敗" aria-label="Permalink to &quot;輸出品質失敗&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Gotcha</th><th>症狀</th><th>修復</th></tr></thead><tbody><tr><td>過早宣告成功</td><td>Sub-agent 說「完成了」但實際沒讀完</td><td>加 Definition of Done checklist</td></tr><tr><td>摘要過長</td><td>Sub-agent 返回 2000 字，污染主 context</td><td>明確限制「回傳 ≤ 600 字」</td></tr><tr><td>無結構輸出</td><td>自由文字難以被主 agent 解析</td><td>要求 JSON 或 markdown 表格格式</td></tr></tbody></table><hr><h2 id="與-karpathy-mnilax-規則的關聯" tabindex="-1">與 Karpathy/Mnilax 規則的關聯 <a class="header-anchor" href="#與-karpathy-mnilax-規則的關聯" aria-label="Permalink to &quot;與 Karpathy/Mnilax 規則的關聯&quot;">​</a></h2><table tabindex="0"><thead><tr><th>規則</th><th>對應模式</th></tr></thead><tbody><tr><td>R1 — Think Before Coding</td><td>Explore-Plan-Act Loop</td></tr><tr><td>R2 — Simplicity First</td><td>Progressive Tool Expansion</td></tr><tr><td>R3 — Surgical Modifications</td><td>Context-Isolated Subagents</td></tr><tr><td>R5 — Latent vs Deterministic</td><td>Command Risk Classification</td></tr><tr><td>R6 — Context Budget</td><td>Tiered Memory</td></tr><tr><td>R9 — Test Intent</td><td>Deterministic Lifecycle Hooks</td></tr><tr><td>R12 — Fail Loud</td><td>Deterministic Lifecycle Hooks</td></tr></tbody></table><hr><h2 id="延伸閱讀" tabindex="-1">延伸閱讀 <a class="header-anchor" href="#延伸閱讀" aria-label="Permalink to &quot;延伸閱讀&quot;">​</a></h2><ul><li><a href="https://code.claude.com/docs/en/sub-agents" target="_blank" rel="noreferrer">Sub-Agents 官方文件</a></li><li><a href="/cc-workspace-docs/resources/best-practices/hooks">Hooks 設計模式</a></li><li><a href="/cc-workspace-docs/lectures/lecture-05-memory-workspace/">Lecture 05：記憶系統與工作區設計</a></li><li><a href="/cc-workspace-docs/lectures/lecture-04-harness-architecture/">Lecture 04：Harness 三層架構</a></li></ul>`,62)])])}const u=a(i,[["render",r]]);export{g as __pageData,u as default};
